  1107→    animateZoomTo(targetZoom, clamped.x, clamped.y, 350); // 350ms for navigation
  1108→
  1109→    // Acknowledge the request
  1110→    onNavigationComplete?.();
  1111→  }, [navigationTarget, isInitialized, zoom, effectiveMinZoom, cameraPos, clampCameraToWorld, animateZoomTo, stopMomentum, stopZoomAnimation, onNavigationComplete]);
  1112→
  1113→  /**
  1114→   * Handle pan start / pinch start
  1115→   *
