  1197→
  1198→      // Find task under cursor
  1199→      const taskId = findTaskAtPosition(
  1200→        e.clientX,
  1201→        e.clientY,
  1202→        rect,
  1203→        camera.x,
  1204→        camera.y,
  1205→        zoom,
  1206→        canvasSize.width,
  1207→        canvasSize.height,
  1208→        tasks
  1209→      );
