  1396→        e.clientX,
  1397→        e.clientY,
  1398→        rect,
  1399→        camera.x,
  1400→        camera.y,
  1401→        zoom,
  1402→        canvasSize.width,
  1403→        canvasSize.height,
  1404→        tasks
  1405→      );
